const title=typeof data.title==='string'&&data.title.trim()?data.title.trim():'Step-by-step guide';
const intro=typeof data.intro==='string'&&data.intro.trim()?data.intro.trim():steps.length+' ordered step'+(steps.length===1?'':'s')+' from start to finish';
const frame=make('section','frame'); frame.setAttribute('aria-label',title);
const heading=make('header','heading'); heading.appendChild(make('div','eyebrow','How to')); heading.appendChild(make('h2','',title)); heading.appendChild(make('p','intro',intro)); frame.appendChild(heading);
if(!steps.length){
  frame.appendChild(make('div','empty','Add at least one step to build the guide.'));
}else{
  const list=make('div','steps');
  steps.forEach((step,index) => {
    const row=make('article','step'); row.appendChild(make('div','number',String(index+1).padStart(2,'0')));
    const card=make('div','card'); const head=make('div','step-head'); head.appendChild(make('h3','',step&&step.title!=null?String(step.title):'Untitled step')); if(step&&step.label) head.appendChild(make('span','label',String(step.label))); card.appendChild(head);
    const body=make('div','body'); const paragraphs=Array.isArray(step&&step.body)?step.body:[step&&step.body]; paragraphs.filter((value)=>value!==null&&value!==undefined&&String(value).trim()).forEach((value)=>body.appendChild(make('p','',String(value)))); card.appendChild(body);
    const bullets=step&&Array.isArray(step.bullets)?step.bullets:[]; if(bullets.length){ const ul=make('ul'); bullets.forEach((value)=>ul.appendChild(make('li','',String(value)))); card.appendChild(ul); }
    if(step&&step.tip&&step.tip.body!=null){
      const variant=['tip','note','warning','success'].includes(step.tip.variant)?step.tip.variant:'tip'; const icons={tip:'✦',note:'i',warning:'!',success:'✓'}; const tip=make('aside','tip '+variant); tip.appendChild(make('span','tip-icon',icons[variant])); const copy=make('div'); copy.appendChild(make('span','tip-title',step.tip.title?String(step.tip.title):variant)); copy.appendChild(make('span','tip-body',String(step.tip.body))); tip.appendChild(copy); card.appendChild(tip);
    }
    row.appendChild(card); list.appendChild(row);
  });
  frame.appendChild(list);
}
root.appendChild(frame);
parent.appendChild(host);
